package org.apache.commons.math3.analysis.integration;

public class SimpsonIntegrator extends BaseAbstractUnivariateIntegrator { public static final int SIMPSON_MAX_ITERATIONS_COUNT = 64 ; public SimpsonIntegrator ( final double relativeAccuracy , final double absoluteAccuracy , final int minimalIterationCount , final int maximalIterationCount ) throws NotStrictlyPositiveException , NumberIsTooSmallException , NumberIsTooLargeException { super ( relativeAccuracy , absoluteAccuracy , minimalIterationCount , maximalIterationCount ) ; if ( maximalIterationCount > SIMPSON_MAX_ITERATIONS_COUNT ) { throw new NumberIsTooLargeException ( maximalIterationCount , SIMPSON_MAX_ITERATIONS_COUNT , false ) ; } } public SimpsonIntegrator ( final int minimalIterationCount , final int maximalIterationCount ) throws NotStrictlyPositiveException , NumberIsTooSmallException , NumberIsTooLargeException { super ( minimalIterationCount , maximalIterationCount ) ; if ( maximalIterationCount > SIMPSON_MAX_ITERATIONS_COUNT ) { throw new NumberIsTooLargeException ( maximalIterationCount , SIMPSON_MAX_ITERATIONS_COUNT , false ) ; } } public SimpsonIntegrator ( ) { super ( DEFAULT_MIN_ITERATIONS_COUNT , SIMPSON_MAX_ITERATIONS_COUNT ) ; } @ Override protected double doIntegrate ( ) throws TooManyEvaluationsException , MaxCountExceededException { TrapezoidIntegrator qtrap = new TrapezoidIntegrator ( ) ; if ( getMinimalIterationCount ( ) == 1 ) { return ( 4 * qtrap . stage ( this , 1 ) - qtrap . stage ( this , 0 ) ) / 3.0 ; } double olds = 0 ; double oldt = qtrap . stage ( this , 0 ) ; while ( true ) { final double t = qtrap . stage ( this , iterations . getCount ( ) ) ; iterations . incrementCount ( ) ; final double s = ( 4 * t - oldt ) / 3.0 ; if ( iterations . getCount ( ) >= getMinimalIterationCount ( ) ) { final double delta = FastMath . abs ( s - olds ) ; final double rLimit = getRelativeAccuracy ( ) * ( FastMath . abs ( olds ) + FastMath . abs ( s ) ) * 0.5 ; if ( ( delta <= rLimit ) || ( delta <= getAbsoluteAccuracy ( ) ) ) { return s ; } } olds = s ; oldt = t ; } } }